-- Performance Analytics
CREATE TABLE IF NOT EXISTS daily_analytics (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    agent_id UUID REFERENCES ai_agents(id) ON DELETE CASCADE,
    date DATE NOT NULL,
    platform VARCHAR(20) NOT NULL,
    
    -- Content metrics
    posts_generated INTEGER DEFAULT 0,
    replies_sent INTEGER DEFAULT 0,
    total_engagements INTEGER DEFAULT 0,
    average_engagement_rate DECIMAL(5,2) DEFAULT 0,
    
    -- Token metrics
    tokens_earned INTEGER DEFAULT 0,
    tokens_spent INTEGER DEFAULT 0,
    
    -- Performance scores
    content_quality_score DECIMAL(3,2) DEFAULT 0,
    audience_growth INTEGER DEFAULT 0,
    viral_coefficient DECIMAL(4,3) DEFAULT 0,
    
    created_at TIMESTAMP DEFAULT NOW(),
    UNIQUE(agent_id, date, platform)
);

-- OAuth temporary tokens storage
CREATE TABLE IF NOT EXISTS oauth_temp_tokens (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    platform VARCHAR(20) NOT NULL,
    oauth_token VARCHAR(255) NOT NULL,
    oauth_token_secret VARCHAR(255) NOT NULL,
    expires_at TIMESTAMP DEFAULT (NOW() + INTERVAL '10 minutes'),
    created_at TIMESTAMP DEFAULT NOW()
);

-- Create indexes for performance (IF NOT EXISTS for idempotent re-runs)
CREATE INDEX IF NOT EXISTS idx_ai_agents_user_id ON ai_agents(user_id);
CREATE INDEX IF NOT EXISTS idx_ai_agents_nft_mint ON ai_agents(nft_mint_address);
CREATE INDEX IF NOT EXISTS idx_ai_agents_active ON ai_agents(is_active);
CREATE INDEX IF NOT EXISTS idx_platform_connections_user ON platform_connections(user_id, platform);
CREATE INDEX IF NOT EXISTS idx_generated_content_agent ON generated_content(agent_id);
CREATE INDEX IF NOT EXISTS idx_generated_content_scheduled ON generated_content(scheduled_for);
CREATE INDEX IF NOT EXISTS idx_generated_content_published ON generated_content(published_at);
-- CREATE INDEX idx_token_transactions_user ON token_transactions(user_id); -- Solana, excluded
CREATE INDEX IF NOT EXISTS idx_daily_analytics_agent_date ON daily_analytics(agent_id, date);
CREATE INDEX IF NOT EXISTS idx_oauth_temp_tokens_expires ON oauth_temp_tokens(expires_at);

-- Create triggers for updated_at timestamps
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ language 'plpgsql';

DROP TRIGGER IF EXISTS update_users_updated_at ON users;
CREATE TRIGGER update_users_updated_at BEFORE UPDATE ON users
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

DROP TRIGGER IF EXISTS update_ai_agents_updated_at ON ai_agents;
CREATE TRIGGER update_ai_agents_updated_at BEFORE UPDATE ON ai_agents
    FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- Clean up expired OAuth tokens
CREATE OR REPLACE FUNCTION cleanup_expired_oauth_tokens()
RETURNS void AS $$
BEGIN
    DELETE FROM oauth_temp_tokens WHERE expires_at < NOW();
END;
$$ LANGUAGE plpgsql;

-- Schedule cleanup every hour (requires pg_cron extension; skipped if cron schema not available, e.g. on managed DBs)
