CREATE TABLE IF NOT EXISTS email_provider_presets (
    id SERIAL PRIMARY KEY,
    name VARCHAR(100) NOT NULL UNIQUE,
    display_name VARCHAR(100) NOT NULL,
    icon VARCHAR(50),
    imap_host VARCHAR(255) NOT NULL,
    imap_port INTEGER DEFAULT 993,
