-- Migration: Add Influencer Marketing Platform
-- Created: 2025-12-10
-- Description: AI-powered platform for discovering brand-safe, authentic creators by topic

-- Table for influencers/creators
CREATE TABLE IF NOT EXISTS influencers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  platform VARCHAR(50) NOT NULL, -- instagram, tiktok, youtube, twitter, etc.
  platform_user_id VARCHAR(255) NOT NULL, -- External platform user ID
  username VARCHAR(255) NOT NULL,
  display_name VARCHAR(255),
  profile_image_url TEXT,
  bio TEXT,
  follower_count INTEGER DEFAULT 0,
  following_count INTEGER DEFAULT 0,
  post_count INTEGER DEFAULT 0,
  engagement_rate DECIMAL(5,2) DEFAULT 0.00, -- Average engagement rate percentage
  authenticity_score DECIMAL(5,2) DEFAULT 0.00, -- AI-calculated authenticity score (0-100)
  brand_safety_score DECIMAL(5,2) DEFAULT 0.00, -- AI-calculated brand safety score (0-100)
  verified BOOLEAN DEFAULT FALSE,
  location VARCHAR(255),
  website_url TEXT,
  email VARCHAR(255),
  phone VARCHAR(50),
  categories TEXT[] DEFAULT '{}', -- Primary categories/topics
  tags TEXT[] DEFAULT '{}', -- Additional tags for discovery
  demographics JSONB DEFAULT '{}'::jsonb, -- Age range, gender, location breakdown
  content_themes JSONB DEFAULT '{}'::jsonb, -- Content themes and topics
  pricing JSONB DEFAULT '{}'::jsonb, -- Pricing information (post, story, reel, etc.)
  availability_status VARCHAR(50) DEFAULT 'available', -- available, busy, unavailable
  last_activity_at TIMESTAMP,
  last_synced_at TIMESTAMP,
  metadata JSONB DEFAULT '{}'::jsonb, -- Additional platform-specific data
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW(),
  UNIQUE(platform, platform_user_id)
);

-- Table for influencer content samples
CREATE TABLE IF NOT EXISTS influencer_content (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  influencer_id UUID NOT NULL REFERENCES influencers(id) ON DELETE CASCADE,
  platform VARCHAR(50) NOT NULL,
  platform_post_id VARCHAR(255) NOT NULL,
  content_type VARCHAR(50) NOT NULL, -- post, story, reel, video, etc.
  content_url TEXT,
  thumbnail_url TEXT,
  caption TEXT,
  hashtags TEXT[] DEFAULT '{}',
  mentions TEXT[] DEFAULT '{}',
  like_count INTEGER DEFAULT 0,
  comment_count INTEGER DEFAULT 0,
  share_count INTEGER DEFAULT 0,
  view_count INTEGER DEFAULT 0,
  engagement_rate DECIMAL(5,2) DEFAULT 0.00,
  topics TEXT[] DEFAULT '{}', -- AI-extracted topics
  sentiment_score DECIMAL(3,2) DEFAULT 0.00, -- -1.0 to 1.0
  brand_safety_flags TEXT[] DEFAULT '{}', -- Any brand safety concerns
  posted_at TIMESTAMP NOT NULL,
  created_at TIMESTAMP DEFAULT NOW(),
  UNIQUE(platform, platform_post_id)
);

-- Table for influencer campaigns (brand-influencer partnerships)
CREATE TABLE IF NOT EXISTS influencer_campaigns (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  name VARCHAR(255) NOT NULL,
  description TEXT,
  campaign_type VARCHAR(50) NOT NULL, -- sponsored_post, product_review, takeover, etc.
  objective VARCHAR(100), -- awareness, conversions, engagement, etc.
  budget DECIMAL(10,2),
  currency VARCHAR(10) DEFAULT 'USD',
  start_date DATE,
  end_date DATE,
  status VARCHAR(50) DEFAULT 'draft', -- draft, active, completed, cancelled
  target_audience JSONB DEFAULT '{}'::jsonb, -- Target demographics
  required_topics TEXT[] DEFAULT '{}', -- Required content topics
  excluded_topics TEXT[] DEFAULT '{}', -- Topics to avoid
  brand_guidelines TEXT, -- Brand guidelines for influencers
  deliverables JSONB DEFAULT '{}'::jsonb, -- Required deliverables
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW()
);

-- Table for campaign-influencer relationships
CREATE TABLE IF NOT EXISTS campaign_influencers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  campaign_id UUID NOT NULL REFERENCES influencer_campaigns(id) ON DELETE CASCADE,
  influencer_id UUID NOT NULL REFERENCES influencers(id) ON DELETE CASCADE,
  status VARCHAR(50) DEFAULT 'pending', -- pending, invited, accepted, declined, active, completed
  role VARCHAR(50), -- primary, secondary, micro, nano
  compensation DECIMAL(10,2),
  compensation_type VARCHAR(50), -- fixed, per_post, commission, product_only
  deliverables JSONB DEFAULT '{}'::jsonb, -- Specific deliverables for this influencer
  notes TEXT,
  performance_metrics JSONB DEFAULT '{}'::jsonb, -- Tracked performance
  invited_at TIMESTAMP,
  responded_at TIMESTAMP,
  started_at TIMESTAMP,
  completed_at TIMESTAMP,
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW(),
  UNIQUE(campaign_id, influencer_id)
);

-- Table for influencer search history and saved searches
CREATE TABLE IF NOT EXISTS influencer_searches (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  search_query TEXT,
  filters JSONB DEFAULT '{}'::jsonb, -- Applied filters
  results_count INTEGER DEFAULT 0,
  saved BOOLEAN DEFAULT FALSE,
  search_type VARCHAR(50) DEFAULT 'discovery', -- discovery, saved, recommendation
  created_at TIMESTAMP DEFAULT NOW()
);

-- Table for saved influencers (user's favorite/bookmarked influencers)
CREATE TABLE IF NOT EXISTS saved_influencers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  influencer_id UUID NOT NULL REFERENCES influencers(id) ON DELETE CASCADE,
  notes TEXT,
  tags TEXT[] DEFAULT '{}',
  created_at TIMESTAMP DEFAULT NOW(),
  UNIQUE(user_id, influencer_id)
);

-- Table for influencer analytics and insights
CREATE TABLE IF NOT EXISTS influencer_analytics (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  influencer_id UUID NOT NULL REFERENCES influencers(id) ON DELETE CASCADE,
  period_start DATE NOT NULL,
  period_end DATE NOT NULL,
  metrics JSONB DEFAULT '{}'::jsonb, -- Engagement, reach, impressions, etc.
  top_performing_content JSONB DEFAULT '[]'::jsonb,
  audience_growth INTEGER DEFAULT 0,
  engagement_trends JSONB DEFAULT '{}'::jsonb,
  topic_performance JSONB DEFAULT '{}'::jsonb, -- Performance by topic
  created_at TIMESTAMP DEFAULT NOW(),
  UNIQUE(influencer_id, period_start, period_end)
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_influencers_platform ON influencers(platform);
CREATE INDEX IF NOT EXISTS idx_influencers_categories ON influencers USING GIN(categories);
CREATE INDEX IF NOT EXISTS idx_influencers_tags ON influencers USING GIN(tags);
CREATE INDEX IF NOT EXISTS idx_influencers_authenticity_score ON influencers(authenticity_score DESC);
CREATE INDEX IF NOT EXISTS idx_influencers_brand_safety_score ON influencers(brand_safety_score DESC);
CREATE INDEX IF NOT EXISTS idx_influencers_engagement_rate ON influencers(engagement_rate DESC);
CREATE INDEX IF NOT EXISTS idx_influencers_follower_count ON influencers(follower_count DESC);
CREATE INDEX IF NOT EXISTS idx_influencer_content_influencer_id ON influencer_content(influencer_id);
CREATE INDEX IF NOT EXISTS idx_influencer_content_topics ON influencer_content USING GIN(topics);
CREATE INDEX IF NOT EXISTS idx_influencer_content_posted_at ON influencer_content(posted_at DESC);
CREATE INDEX IF NOT EXISTS idx_influencer_campaigns_user_id ON influencer_campaigns(user_id);
CREATE INDEX IF NOT EXISTS idx_influencer_campaigns_status ON influencer_campaigns(status);
CREATE INDEX IF NOT EXISTS idx_campaign_influencers_campaign_id ON campaign_influencers(campaign_id);
CREATE INDEX IF NOT EXISTS idx_campaign_influencers_influencer_id ON campaign_influencers(influencer_id);
CREATE INDEX IF NOT EXISTS idx_campaign_influencers_status ON campaign_influencers(status);
CREATE INDEX IF NOT EXISTS idx_influencer_searches_user_id ON influencer_searches(user_id);
CREATE INDEX IF NOT EXISTS idx_saved_influencers_user_id ON saved_influencers(user_id);
CREATE INDEX IF NOT EXISTS idx_influencer_analytics_influencer_id ON influencer_analytics(influencer_id);

-- Add comments
COMMENT ON TABLE influencers IS 'Influencers/creators discovered and tracked on the platform';
COMMENT ON TABLE influencer_content IS 'Content samples from influencers for analysis';
COMMENT ON TABLE influencer_campaigns IS 'Brand campaigns involving influencers';
COMMENT ON TABLE campaign_influencers IS 'Relationships between campaigns and influencers';
COMMENT ON TABLE influencer_searches IS 'User search history for influencer discovery';
COMMENT ON TABLE saved_influencers IS 'User-saved/bookmarked influencers';
COMMENT ON TABLE influencer_analytics IS 'Analytics and insights for influencers';




-- ========== Backend\database\migrations\add_keyword_intelligence.sql ==========

-- Keyword & Hashtag Intelligence Module schema
-- Monitors, snapshots, alerts, usage, and collections
-- Created: 2025-12-14

CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Table for keyword/hashtag monitors
CREATE TABLE IF NOT EXISTS keyword_monitors (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    keyword VARCHAR(255) NOT NULL, -- The keyword or hashtag to monitor
    monitor_type VARCHAR(20) NOT NULL DEFAULT 'keyword' CHECK (monitor_type IN ('keyword', 'hashtag')),
    platform VARCHAR(50) NOT NULL DEFAULT 'twitter' CHECK (platform IN ('twitter', 'instagram', 'google', 'all')),
    is_active BOOLEAN DEFAULT TRUE,
    
    -- Alert settings
    sentiment_threshold DECIMAL(5,2) DEFAULT 5.0, -- Alert if sentiment changes by this amount
    mention_spike_threshold INTEGER DEFAULT 5, -- Alert if mentions increase by this percentage
    track_influencers BOOLEAN DEFAULT TRUE,
    influencer_handles TEXT[], -- Specific influencers to track
    
    -- Monitoring settings
    monitoring_frequency VARCHAR(20) DEFAULT '15min' CHECK (monitoring_frequency IN ('5min', '15min', '30min', '1hour', '6hour', '24hour')),
    exclude_keywords TEXT[], -- Keywords to exclude from results
    
    -- Content generation settings
    auto_post_enabled BOOLEAN DEFAULT FALSE,
    post_channels TEXT[] DEFAULT ARRAY[]::TEXT[],
    content_style VARCHAR(50) DEFAULT 'professional',
    
    -- Metadata
    tags TEXT[] DEFAULT '{}', -- User-defined tags for organization
    notes TEXT, -- User notes about this monitor
    collection_id UUID, -- Optional: link to a collection
    
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_keyword_monitors_user ON keyword_monitors(user_id);
CREATE INDEX IF NOT EXISTS idx_keyword_monitors_active ON keyword_monitors(is_active);
CREATE INDEX IF NOT EXISTS idx_keyword_monitors_keyword ON keyword_monitors(keyword);
CREATE INDEX IF NOT EXISTS idx_keyword_monitors_type ON keyword_monitors(monitor_type);

-- Table for keyword/hashtag snapshots (historical data)
CREATE TABLE IF NOT EXISTS keyword_snapshots (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    monitor_id UUID NOT NULL REFERENCES keyword_monitors(id) ON DELETE CASCADE,
    keyword VARCHAR(255) NOT NULL,
    
    -- Sentiment metrics
    sentiment_score DECIMAL(5,2), -- -100 to 100
    mention_count INTEGER DEFAULT 0,
    positive_count INTEGER DEFAULT 0,
    negative_count INTEGER DEFAULT 0,
    neutral_count INTEGER DEFAULT 0,
    
    -- Engagement metrics
    total_likes INTEGER DEFAULT 0,
    total_retweets INTEGER DEFAULT 0,
    total_replies INTEGER DEFAULT 0,
    total_views INTEGER DEFAULT 0,
    engagement_rate DECIMAL(5,2) DEFAULT 0.00,
    
    -- Key phrases detected
    trending_phrases TEXT[],
    related_keywords TEXT[], -- AI-discovered related keywords
    
    -- Influencer activity
    influencer_mentions INTEGER DEFAULT 0,
    top_influencer_sentiment VARCHAR(20), -- bullish, bearish, neutral
    top_influencers JSONB DEFAULT '[]'::jsonb, -- Array of top influencer data
    
    -- Geographic data (when available)
    top_locations TEXT[],
    
    -- Raw data
    sample_posts JSONB DEFAULT '[]'::jsonb, -- Sample of top posts
    raw_data JSONB DEFAULT '{}'::jsonb, -- Full raw response from API
    
    snapshot_time TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_keyword_snapshots_monitor ON keyword_snapshots(monitor_id);
CREATE INDEX IF NOT EXISTS idx_keyword_snapshots_time ON keyword_snapshots(snapshot_time);
CREATE INDEX IF NOT EXISTS idx_keyword_snapshots_keyword ON keyword_snapshots(keyword, snapshot_time);

-- Table for keyword/hashtag alerts
CREATE TABLE IF NOT EXISTS keyword_alerts (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    monitor_id UUID NOT NULL REFERENCES keyword_monitors(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    
    alert_type VARCHAR(50) NOT NULL, -- sentiment_shift, mention_spike, influencer_activity, trending
    severity VARCHAR(20) DEFAULT 'medium' CHECK (severity IN ('low', 'medium', 'high', 'critical')),
    
    title VARCHAR(200) NOT NULL,
    message TEXT NOT NULL,
    data JSONB, -- Additional alert data
    
    -- Alert details
    previous_value DECIMAL(10,2), -- Previous metric value
    current_value DECIMAL(10,2), -- Current metric value
    change_percent DECIMAL(5,2), -- Percentage change
    
    -- Notification channels
    channels_sent TEXT[], -- Where alert was sent (email, in-app, etc.)
    content_generated_id UUID, -- If auto-post was generated
    
    is_read BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_keyword_alerts_user ON keyword_alerts(user_id);
CREATE INDEX IF NOT EXISTS idx_keyword_alerts_monitor ON keyword_alerts(monitor_id);
CREATE INDEX IF NOT EXISTS idx_keyword_alerts_created ON keyword_alerts(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_keyword_alerts_read ON keyword_alerts(is_read, created_at DESC);

-- Table for API usage tracking
CREATE TABLE IF NOT EXISTS keyword_api_usage (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    
    operation_type VARCHAR(50) NOT NULL, -- keyword_x_search, hashtag_x_search, keyword_sentiment_analysis, etc.
    tokens_used INTEGER DEFAULT 0,
    api_calls INTEGER DEFAULT 1,
    
    grok_model VARCHAR(50),
    sources_used INTEGER DEFAULT 0,
    
    estimated_cost_usd DECIMAL(10,6),
    credits_deducted DECIMAL(10,4),
    
    monitor_id UUID REFERENCES keyword_monitors(id) ON DELETE SET NULL,
    keyword VARCHAR(255),
    
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_keyword_api_usage_user ON keyword_api_usage(user_id);
CREATE INDEX IF NOT EXISTS idx_keyword_api_usage_created ON keyword_api_usage(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_keyword_api_usage_operation ON keyword_api_usage(operation_type, created_at);

-- Table for hashtag/keyword collections (organizational tool)
CREATE TABLE IF NOT EXISTS keyword_collections (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    name VARCHAR(200) NOT NULL,
    description TEXT,
    color VARCHAR(20), -- For UI organization
    tags TEXT[] DEFAULT '{}',
    
    -- Statistics (cached)
    total_keywords INTEGER DEFAULT 0,
    total_mentions INTEGER DEFAULT 0,
    avg_sentiment DECIMAL(5,2) DEFAULT 0.00,
    
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_keyword_collections_user ON keyword_collections(user_id);

-- Table for keyword research results (discovery tool)
CREATE TABLE IF NOT EXISTS keyword_research (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    
    research_type VARCHAR(50) NOT NULL, -- trending, related, competitor, suggestion
    query VARCHAR(255) NOT NULL, -- The keyword/hashtag researched
    platform VARCHAR(50) DEFAULT 'twitter',
    
    -- Research results
    results JSONB DEFAULT '{}'::jsonb, -- Structured research data
    trending_keywords TEXT[], -- Discovered trending keywords
    related_keywords TEXT[], -- Related keywords
    suggested_hashtags TEXT[], -- Suggested hashtags
    competitor_keywords TEXT[], -- Competitor keywords found
    
    -- Metrics
    search_volume INTEGER, -- Estimated search volume
    competition_level VARCHAR(20), -- low, medium, high
    trend_direction VARCHAR(20), -- rising, falling, stable
    
    -- Metadata
    notes TEXT,
    saved BOOLEAN DEFAULT FALSE,
    
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_keyword_research_user ON keyword_research(user_id);
CREATE INDEX IF NOT EXISTS idx_keyword_research_query ON keyword_research(query);
CREATE INDEX IF NOT EXISTS idx_keyword_research_saved ON keyword_research(saved, created_at DESC);

-- Add foreign key for collection_id in keyword_monitors
DO $$ 
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint 
        WHERE conname = 'keyword_monitors_collection_id_fkey'
    ) THEN
        ALTER TABLE keyword_monitors
        ADD CONSTRAINT keyword_monitors_collection_id_fkey
        FOREIGN KEY (collection_id) REFERENCES keyword_collections(id) ON DELETE SET NULL;
    END IF;
END $$;




