-- ========== Backend\database\migrations\create_woocommerce_order_tables.sql ==========

-- Create WooCommerce orders and customers tables for order management
-- This allows AI agents to access order details and customer purchase history

-- WooCommerce stores table (one per user/company)
CREATE TABLE IF NOT EXISTS woocommerce_stores (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    company_profile_id UUID REFERENCES company_profiles(id) ON DELETE SET NULL,
    store_url VARCHAR(500) NOT NULL,
    store_name VARCHAR(255),
    api_key VARCHAR(255), -- WooCommerce REST API key (encrypted)
    api_secret VARCHAR(255), -- WooCommerce REST API secret (encrypted)
    is_active BOOLEAN DEFAULT true,
    last_sync_at TIMESTAMP WITH TIME ZONE,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE(user_id, store_url)
);

-- WooCommerce customers table
CREATE TABLE IF NOT EXISTS woocommerce_customers (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    woocommerce_store_id UUID NOT NULL REFERENCES woocommerce_stores(id) ON DELETE CASCADE,
    woocommerce_customer_id BIGINT NOT NULL,
    email VARCHAR(255),
    first_name VARCHAR(255),
    last_name VARCHAR(255),
    phone VARCHAR(50),
    total_spent DECIMAL(10,2) DEFAULT 0,
    orders_count INTEGER DEFAULT 0,
    date_created TIMESTAMP WITH TIME ZONE,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE(woocommerce_store_id, woocommerce_customer_id)
);

-- WooCommerce orders table
CREATE TABLE IF NOT EXISTS woocommerce_orders (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    woocommerce_store_id UUID NOT NULL REFERENCES woocommerce_stores(id) ON DELETE CASCADE,
    woocommerce_order_id BIGINT NOT NULL,
    order_number VARCHAR(50),
    woocommerce_customer_id UUID REFERENCES woocommerce_customers(id) ON DELETE SET NULL,
    customer_email VARCHAR(255),
    customer_first_name VARCHAR(255),
    customer_last_name VARCHAR(255),
    status VARCHAR(50) NOT NULL, -- pending, processing, on-hold, completed, cancelled, refunded, failed
    currency VARCHAR(10) DEFAULT 'USD',
    total DECIMAL(10,2) NOT NULL DEFAULT 0,
    subtotal DECIMAL(10,2) DEFAULT 0,
    total_tax DECIMAL(10,2) DEFAULT 0,
    shipping_total DECIMAL(10,2) DEFAULT 0,
    discount_total DECIMAL(10,2) DEFAULT 0,
    payment_method VARCHAR(100),
    payment_method_title VARCHAR(255),
    date_created TIMESTAMP WITH TIME ZONE,
    date_modified TIMESTAMP WITH TIME ZONE,
    date_completed TIMESTAMP WITH TIME ZONE,
    billing_address JSONB, -- Full billing address as JSON
    shipping_address JSONB, -- Full shipping address as JSON
    line_items JSONB, -- Array of order line items
    shipping_lines JSONB, -- Array of shipping methods
    fee_lines JSONB, -- Array of fees
    coupon_lines JSONB, -- Array of applied coupons
    metadata JSONB, -- Additional order metadata
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE(woocommerce_store_id, woocommerce_order_id)
);

-- Create indexes for better performance
CREATE INDEX IF NOT EXISTS idx_woocommerce_stores_user_id ON woocommerce_stores(user_id);
CREATE INDEX IF NOT EXISTS idx_woocommerce_stores_company_profile ON woocommerce_stores(company_profile_id);
CREATE INDEX IF NOT EXISTS idx_woocommerce_customers_store ON woocommerce_customers(woocommerce_store_id);
CREATE INDEX IF NOT EXISTS idx_woocommerce_customers_email ON woocommerce_customers(email);
CREATE INDEX IF NOT EXISTS idx_woocommerce_orders_store ON woocommerce_orders(woocommerce_store_id);
CREATE INDEX IF NOT EXISTS idx_woocommerce_orders_customer ON woocommerce_orders(woocommerce_customer_id);
CREATE INDEX IF NOT EXISTS idx_woocommerce_orders_customer_email ON woocommerce_orders(customer_email);
CREATE INDEX IF NOT EXISTS idx_woocommerce_orders_status ON woocommerce_orders(status);
CREATE INDEX IF NOT EXISTS idx_woocommerce_orders_date_created ON woocommerce_orders(date_created);

-- Comments
COMMENT ON TABLE woocommerce_stores IS 'Stores WooCommerce store connections for each user';
COMMENT ON TABLE woocommerce_customers IS 'Stores WooCommerce customer information synced from stores';
COMMENT ON TABLE woocommerce_orders IS 'Stores WooCommerce order details for AI agent access and order management';




-- ========== Backend\database\migrations\enable_pgvector.sql ==========

-- Enable pgvector Extension
-- Run this script FIRST if you get "type vector does not exist" error
-- 
-- IMPORTANT: This requires superuser privileges or the extension must be pre-installed
-- 
-- For Aiven PostgreSQL:
--   1. Go to Aiven Console
--   2. Select your PostgreSQL service
--   3. Go to "Extensions" tab
--   4. Enable "vector" extension
--
-- For standard PostgreSQL:
--   1. Install pgvector on your server first
--   2. Then run this script as superuser

-- Check if pgvector is available
DO $$
BEGIN
    -- Try to create the extension
    CREATE EXTENSION IF NOT EXISTS vector;
    RAISE NOTICE '✅ pgvector extension enabled successfully!';
    RAISE NOTICE 'You can now run the create_custom_business_data.sql migration.';
EXCEPTION
    WHEN insufficient_privilege THEN
        RAISE EXCEPTION '❌ Insufficient privileges. You need superuser access or the extension must be enabled by a database administrator.';
    WHEN undefined_file THEN
        RAISE EXCEPTION '❌ pgvector extension files not found. Please install pgvector first:
        
        Ubuntu/Debian: sudo apt-get install postgresql-XX-vector
        macOS: brew install pgvector
        Or compile from source: https://github.com/pgvector/pgvector';
    WHEN OTHERS THEN
        RAISE EXCEPTION '❌ Error enabling pgvector: %', SQLERRM;
END $$;

-- Verify installation
SELECT 
    extname as extension_name,
    extversion as version
FROM pg_extension 
WHERE extname = 'vector';




-- ========== Backend\database\migrations\enhance_characters_to_avatars.sql ==========

-- Enhanced Avatar System Migration
-- Transforms characters table into a comprehensive avatar system with video/photo support and multiple looks

-- Add new columns to characters table for avatar functionality
DO $$ 
BEGIN
  -- Avatar type: 'video', 'photo', 'ai_generated', 'images' (legacy)
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'avatar_type') THEN
    ALTER TABLE characters ADD COLUMN avatar_type VARCHAR(50) DEFAULT 'images';
  END IF;

  -- Processing status: 'pending', 'processing', 'completed', 'failed'
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'processing_status') THEN
    ALTER TABLE characters ADD COLUMN processing_status VARCHAR(50) DEFAULT 'completed';
  END IF;

  -- Processing progress (0-100)
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'processing_progress') THEN
    ALTER TABLE characters ADD COLUMN processing_progress INTEGER DEFAULT 100;
  END IF;

  -- HeyGen avatar ID (if using HeyGen API)
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'heygen_avatar_id') THEN
    ALTER TABLE characters ADD COLUMN heygen_avatar_id VARCHAR(255);
  END IF;

  -- Video URL for video-based avatars
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'video_url') THEN
    ALTER TABLE characters ADD COLUMN video_url TEXT;
  END IF;

  -- Number of looks
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'looks_count') THEN
    ALTER TABLE characters ADD COLUMN looks_count INTEGER DEFAULT 1;
  END IF;

  -- Processing error message
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'processing_error') THEN
    ALTER TABLE characters ADD COLUMN processing_error TEXT;
  END IF;

  -- Processing started at timestamp
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'processing_started_at') THEN
    ALTER TABLE characters ADD COLUMN processing_started_at TIMESTAMP WITH TIME ZONE;
  END IF;

  -- Processing completed at timestamp
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns 
                 WHERE table_name = 'characters' AND column_name = 'processing_completed_at') THEN
    ALTER TABLE characters ADD COLUMN processing_completed_at TIMESTAMP WITH TIME ZONE;
  END IF;
END $$;

-- Create avatar_looks table for multiple looks per avatar
CREATE TABLE IF NOT EXISTS avatar_looks (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    character_id UUID NOT NULL REFERENCES characters(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    
    -- Look metadata
    name VARCHAR(255) NOT NULL,
    description TEXT,
    look_type VARCHAR(50) DEFAULT 'photo', -- 'photo', 'video', 'ai_generated'
    
    -- Look media
    image_url TEXT,
    video_url TEXT,
    thumbnail_url TEXT,
    
    -- Look settings
    outfit_type VARCHAR(50), -- 'casual', 'formal', 'athletic', 'business', etc.
    setting VARCHAR(100), -- 'office', 'gym', 'vacation', 'studio', etc.
    pose VARCHAR(50), -- 'standing', 'sitting', 'walking', etc.
    expression VARCHAR(50), -- 'smiling', 'neutral', 'serious', etc.
    
    -- Look configuration
    is_default BOOLEAN DEFAULT false,
    is_active BOOLEAN DEFAULT true,
    order_index INTEGER DEFAULT 0,
    
    -- Metadata
    metadata JSONB DEFAULT '{}',
    
    -- Timestamps
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Indexes for avatar_looks
CREATE INDEX IF NOT EXISTS idx_avatar_looks_character ON avatar_looks(character_id);
CREATE INDEX IF NOT EXISTS idx_avatar_looks_user ON avatar_looks(user_id);
CREATE INDEX IF NOT EXISTS idx_avatar_looks_default ON avatar_looks(character_id, is_default) WHERE is_default = true;
CREATE INDEX IF NOT EXISTS idx_avatar_looks_active ON avatar_looks(character_id, is_active) WHERE is_active = true;
CREATE INDEX IF NOT EXISTS idx_avatar_looks_order ON avatar_looks(character_id, order_index);

-- Create avatar_processing_jobs table for tracking processing status
CREATE TABLE IF NOT EXISTS avatar_processing_jobs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    character_id UUID NOT NULL REFERENCES characters(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    
    -- Job metadata
    job_type VARCHAR(50) NOT NULL, -- 'video_processing', 'photo_processing', 'look_generation'
    status VARCHAR(50) DEFAULT 'pending', -- 'pending', 'processing', 'completed', 'failed', 'cancelled'
    
    -- Progress tracking
    progress INTEGER DEFAULT 0, -- 0-100
    current_step VARCHAR(255),
    total_steps INTEGER,
    
    -- Input/output
    input_data JSONB, -- Original upload data
    output_data JSONB, -- Processing results
    error_message TEXT,
    
    -- External service IDs (e.g., HeyGen job ID)
    external_job_id VARCHAR(255),
    external_service VARCHAR(50), -- 'heygen', 'internal', etc.
    
    -- Timestamps
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    started_at TIMESTAMP WITH TIME ZONE,
    completed_at TIMESTAMP WITH TIME ZONE,
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Indexes for avatar_processing_jobs
CREATE INDEX IF NOT EXISTS idx_avatar_jobs_character ON avatar_processing_jobs(character_id);
CREATE INDEX IF NOT EXISTS idx_avatar_jobs_user ON avatar_processing_jobs(user_id);
CREATE INDEX IF NOT EXISTS idx_avatar_jobs_status ON avatar_processing_jobs(status);
CREATE INDEX IF NOT EXISTS idx_avatar_jobs_type ON avatar_processing_jobs(job_type);
CREATE INDEX IF NOT EXISTS idx_avatar_jobs_external ON avatar_processing_jobs(external_service, external_job_id) WHERE external_job_id IS NOT NULL;

-- Create avatar_videos table for storing uploaded video files
CREATE TABLE IF NOT EXISTS avatar_videos (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    character_id UUID REFERENCES characters(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    
    -- Video metadata
    filename VARCHAR(255) NOT NULL,
    file_path TEXT NOT NULL,
    file_size BIGINT, -- in bytes
    duration DECIMAL(10, 2), -- in seconds
    resolution VARCHAR(20), -- e.g., '1920x1080'
    format VARCHAR(20), -- 'mp4', 'mov', 'webm'
    
    -- Video properties
    fps INTEGER, -- frames per second
    bitrate INTEGER, -- in kbps
    codec VARCHAR(50),
    
    -- Upload metadata
    upload_method VARCHAR(50), -- 'file_upload', 'webcam', 'phone', 'google_drive'
    upload_source TEXT, -- Original source URL if from Google Drive
    
    -- Processing status
    is_processed BOOLEAN DEFAULT false,
    processing_status VARCHAR(50) DEFAULT 'pending',
    
    -- Metadata
    metadata JSONB DEFAULT '{}',
    
    -- Timestamps
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Indexes for avatar_videos
CREATE INDEX IF NOT EXISTS idx_avatar_videos_character ON avatar_videos(character_id);
CREATE INDEX IF NOT EXISTS idx_avatar_videos_user ON avatar_videos(user_id);
CREATE INDEX IF NOT EXISTS idx_avatar_videos_processed ON avatar_videos(is_processed);

-- Update existing characters to have default values
UPDATE characters 
SET 
    avatar_type = COALESCE(avatar_type, 'images'),
    processing_status = COALESCE(processing_status, 'completed'),
    processing_progress = COALESCE(processing_progress, 100),
    looks_count = 1
WHERE avatar_type IS NULL OR processing_status IS NULL;

-- Add comments for documentation
COMMENT ON TABLE avatar_looks IS 'Stores multiple looks (outfits, poses, settings) for each avatar';
COMMENT ON TABLE avatar_processing_jobs IS 'Tracks processing jobs for avatar creation and look generation';
COMMENT ON TABLE avatar_videos IS 'Stores uploaded video files for video-based avatar creation';

COMMENT ON COLUMN characters.avatar_type IS 'Type of avatar: video, photo, ai_generated, or images (legacy)';
COMMENT ON COLUMN characters.processing_status IS 'Current processing status: pending, processing, completed, failed';
COMMENT ON COLUMN characters.heygen_avatar_id IS 'HeyGen API avatar ID if using HeyGen service';
COMMENT ON COLUMN characters.video_url IS 'URL to uploaded video file for video-based avatars';




-- ========== Backend\database\migrations\fix_conversations_schema.sql ==========

-- Fix conversations table schema
-- IMPORTANT: This table is used for BOTH voice chat (user_id, agent_id) AND chat messaging (created_by)
-- We need to preserve user_id for voice chat and ensure created_by exists for chat messaging

DO $$
DECLARE
    has_user_id BOOLEAN;
    has_created_by BOOLEAN;
    has_agent_id BOOLEAN;
BEGIN
    -- Check if user_id column exists (for voice chat)
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_schema = 'public' 
        AND table_name = 'conversations' 
        AND column_name = 'user_id'
    ) INTO has_user_id;

    -- Check if created_by column exists (for chat messaging)
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_schema = 'public' 
        AND table_name = 'conversations' 
        AND column_name = 'created_by'
    ) INTO has_created_by;

    -- Check if agent_id exists (indicates voice chat table)
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_schema = 'public' 
        AND table_name = 'conversations' 
        AND column_name = 'agent_id'
    ) INTO has_agent_id;

    -- If created_by doesn't exist, add it (for chat messaging)
    -- We keep user_id for voice chat compatibility
    IF NOT has_created_by THEN
        ALTER TABLE conversations ADD COLUMN created_by UUID REFERENCES users(id);
        RAISE NOTICE 'Added created_by column for chat messaging';
    ELSE
        RAISE NOTICE 'created_by column already exists';
    END IF;

    -- If both user_id and agent_id exist, this is a voice chat table
    -- We keep both user_id and created_by - they serve different purposes
    IF has_user_id AND has_agent_id THEN
        RAISE NOTICE 'Table has both voice chat (user_id, agent_id) and chat messaging (created_by) columns';
    END IF;

    -- Make user_id nullable for chat messaging (voice chat can still use it)
    -- This allows chat conversations to be created without user_id
    IF has_user_id THEN
        -- Check if user_id is currently NOT NULL
        IF EXISTS (
            SELECT 1 FROM information_schema.columns 
            WHERE table_schema = 'public' 
            AND table_name = 'conversations' 
            AND column_name = 'user_id'
            AND is_nullable = 'NO'
        ) THEN
            -- Make it nullable to allow chat messaging
            ALTER TABLE conversations ALTER COLUMN user_id DROP NOT NULL;
            RAISE NOTICE 'Made user_id nullable to support both voice chat and chat messaging';
        END IF;
    END IF;

    -- Make agent_id nullable for chat messaging (voice chat can still use it)
    -- This allows chat conversations to be created without agent_id
    IF has_agent_id THEN
        -- Check if agent_id is currently NOT NULL
        IF EXISTS (
            SELECT 1 FROM information_schema.columns 
            WHERE table_schema = 'public' 
            AND table_name = 'conversations' 
            AND column_name = 'agent_id'
            AND is_nullable = 'NO'
        ) THEN
            -- Make it nullable to allow chat messaging
            ALTER TABLE conversations ALTER COLUMN agent_id DROP NOT NULL;
            RAISE NOTICE 'Made agent_id nullable to support both voice chat and chat messaging';
        END IF;
    END IF;

    -- Note: We keep created_by nullable for now to avoid breaking existing data
    -- Chat messaging code should always provide created_by when creating conversations
END $$;

-- Verify the final schema
SELECT 
    column_name,
    data_type,
    is_nullable,
    column_default
FROM information_schema.columns
WHERE table_schema = 'public' 
  AND table_name = 'conversations'
  AND column_name IN ('user_id', 'agent_id', 'created_by')
ORDER BY ordinal_position;




