WHERE auth_token IS NULL;



-- ========== Backend\src\database\migrations\add_company_profile_context.sql ==========

-- Adds richer context to company profiles plus supporting tables

BEGIN;

ALTER TABLE company_profiles
    ADD COLUMN IF NOT EXISTS legal_name VARCHAR(200),
    ADD COLUMN IF NOT EXISTS business_type VARCHAR(100),
    ADD COLUMN IF NOT EXISTS registration_number VARCHAR(100),
    ADD COLUMN IF NOT EXISTS time_zone VARCHAR(100),
    ADD COLUMN IF NOT EXISTS headquarters_address JSONB DEFAULT '{}'::jsonb,
    ADD COLUMN IF NOT EXISTS support_email VARCHAR(200),
    ADD COLUMN IF NOT EXISTS support_phone VARCHAR(50),
    ADD COLUMN IF NOT EXISTS whatsapp_number VARCHAR(50),
    ADD COLUMN IF NOT EXISTS support_hours TEXT,
    ADD COLUMN IF NOT EXISTS primary_currency_code VARCHAR(10),
    ADD COLUMN IF NOT EXISTS primary_currency_symbol VARCHAR(10),
    ADD COLUMN IF NOT EXISTS accepted_currencies TEXT[] DEFAULT '{}'::text[],
    ADD COLUMN IF NOT EXISTS preferred_languages TEXT[] DEFAULT '{}'::text[],
    ADD COLUMN IF NOT EXISTS shipping_regions TEXT[] DEFAULT '{}'::text[],
    ADD COLUMN IF NOT EXISTS operating_countries TEXT[] DEFAULT '{}'::text[],
    ADD COLUMN IF NOT EXISTS tax_policy TEXT,
    ADD COLUMN IF NOT EXISTS vat_number VARCHAR(100),
    ADD COLUMN IF NOT EXISTS return_policy TEXT,
    ADD COLUMN IF NOT EXISTS refund_policy TEXT,
    ADD COLUMN IF NOT EXISTS warranty_policy TEXT,
    ADD COLUMN IF NOT EXISTS business_hours JSONB DEFAULT '{}'::jsonb;

CREATE TABLE IF NOT EXISTS company_locations (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    company_profile_id UUID REFERENCES company_profiles(id) ON DELETE CASCADE,
    location_name VARCHAR(200) NOT NULL,
    location_type VARCHAR(50),
    address JSONB DEFAULT '{}'::jsonb,
    contact_email VARCHAR(200),
    contact_phone VARCHAR(50),
    timezone VARCHAR(100),
    hours JSONB DEFAULT '{}'::jsonb,
    is_primary BOOLEAN DEFAULT false,
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS company_faqs (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    company_profile_id UUID REFERENCES company_profiles(id) ON DELETE CASCADE,
    question TEXT NOT NULL,
    answer TEXT NOT NULL,
    category VARCHAR(100),
    tags TEXT[] DEFAULT '{}'::text[],
    sort_order INTEGER DEFAULT 0,
    is_active BOOLEAN DEFAULT true,
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Ensure updated_at columns refresh automatically
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_trigger
        WHERE tgname = 'update_company_locations_updated_at'
    ) THEN
        CREATE TRIGGER update_company_locations_updated_at
        BEFORE UPDATE ON company_locations
        FOR EACH ROW EXECUTE PROCEDURE update_updated_at_column();
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM pg_trigger
        WHERE tgname = 'update_company_faqs_updated_at'
    ) THEN
        CREATE TRIGGER update_company_faqs_updated_at
        BEFORE UPDATE ON company_faqs
        FOR EACH ROW EXECUTE PROCEDURE update_updated_at_column();
    END IF;
END;
$$;

COMMIT;




