VALUES 
  ('write_operations_enabled', 'true', 'Master switch for all write operations (posts, replies, etc.)', NOW()),
  ('write_operations_posts_enabled', 'true', 'Allow scheduled posts to be published', NOW()),
  ('write_operations_replies_enabled', 'false', 'Allow replies to tweets/mentions', NOW()),
  ('write_operations_engagement_enabled', 'false', 'Allow topic-based engagement (replies to relevant tweets)', NOW()),
  ('write_operations_mentions_enabled', 'false', 'Allow replies to mentions', NOW())
ON CONFLICT (config_key) DO NOTHING;

-- Create trigger for updated_at if it doesn't exist
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ language 'plpgsql';

-- Create trigger for system_config updated_at if it doesn't exist
DROP TRIGGER IF EXISTS update_system_config_updated_at ON system_config;
CREATE TRIGGER update_system_config_updated_at 
    BEFORE UPDATE ON system_config
    FOR EACH ROW EXECUTE PROCEDURE update_updated_at_column();




-- ========== Backend\src\database\migrations\create_ai_meeting_prep_table.sql ==========

-- ========== user_calendar_accounts + calendar_events (required by ai_meeting_prep below) ==========
CREATE TABLE IF NOT EXISTS user_calendar_accounts (
  id SERIAL PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  provider VARCHAR(50) NOT NULL DEFAULT 'google',
  email_address VARCHAR(255) NOT NULL DEFAULT '',
  access_token TEXT NOT NULL DEFAULT '',
  refresh_token TEXT NOT NULL DEFAULT '',
  token_expires_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  scope TEXT,
  is_active BOOLEAN DEFAULT true,
  last_sync_at TIMESTAMP,
  sync_token TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(user_id, provider, email_address)
);
CREATE INDEX IF NOT EXISTS idx_calendar_accounts_user ON user_calendar_accounts(user_id);
CREATE INDEX IF NOT EXISTS idx_calendar_accounts_active ON user_calendar_accounts(is_active);

CREATE TABLE IF NOT EXISTS calendar_events (
  id SERIAL PRIMARY KEY,
  account_id INTEGER NOT NULL REFERENCES user_calendar_accounts(id) ON DELETE CASCADE,
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  provider_event_id VARCHAR(255) NOT NULL DEFAULT '',
  calendar_id VARCHAR(255) NOT NULL DEFAULT '',
  summary TEXT,
  description TEXT,
  location TEXT,
  start_time TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  end_time TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  start_timezone VARCHAR(100),
  end_timezone VARCHAR(100),
  is_all_day BOOLEAN DEFAULT false,
  status VARCHAR(50),
  attendees JSONB,
  organizer JSONB,
  recurring_event_id VARCHAR(255),
  recurrence TEXT[],
  conference_data JSONB,
  reminders JSONB,
  color_id VARCHAR(50),
  visibility VARCHAR(50),
  transparency VARCHAR(50),
  html_link TEXT,
  hangout_link TEXT,
  meet_link TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(account_id, provider_event_id)
);
CREATE INDEX IF NOT EXISTS idx_events_account ON calendar_events(account_id);
CREATE INDEX IF NOT EXISTS idx_events_user ON calendar_events(user_id);
CREATE INDEX IF NOT EXISTS idx_events_start_time ON calendar_events(start_time);
CREATE INDEX IF NOT EXISTS idx_events_end_time ON calendar_events(end_time);
CREATE INDEX IF NOT EXISTS idx_events_calendar ON calendar_events(calendar_id);
CREATE INDEX IF NOT EXISTS idx_events_status ON calendar_events(status);

-- AI Meeting Prep Table
-- Stores AI-generated meeting preparation briefs

-- Drop table if exists (for clean migration)
DROP TABLE IF EXISTS ai_meeting_prep CASCADE;

-- Create table
CREATE TABLE ai_meeting_prep (
  id SERIAL PRIMARY KEY,
  event_id INTEGER NOT NULL REFERENCES calendar_events(id) ON DELETE CASCADE,
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  
  -- Meeting context
  meeting_summary TEXT,
  attendee_context JSONB DEFAULT '[]',
  related_emails JSONB DEFAULT '[]',
  past_meetings JSONB DEFAULT '[]',
  
  -- AI-generated content
  discussion_topics TEXT[],
  suggested_questions TEXT[],
  preparation_checklist TEXT[],
  key_context TEXT,
  estimated_prep_time INTEGER, -- in minutes
  
  -- Metadata
  generated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  expires_at TIMESTAMP DEFAULT (CURRENT_TIMESTAMP + INTERVAL '24 hours'),
  
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  
  -- Constraints
  UNIQUE(event_id, user_id)
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_ai_meeting_prep_event_id ON ai_meeting_prep(event_id);
CREATE INDEX IF NOT EXISTS idx_ai_meeting_prep_user_id ON ai_meeting_prep(user_id);
CREATE INDEX IF NOT EXISTS idx_ai_meeting_prep_expires_at ON ai_meeting_prep(expires_at);

-- Trigger to update updated_at timestamp
CREATE OR REPLACE FUNCTION update_ai_meeting_prep_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = CURRENT_TIMESTAMP;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trigger_update_ai_meeting_prep_updated_at ON ai_meeting_prep;
CREATE TRIGGER trigger_update_ai_meeting_prep_updated_at
  BEFORE UPDATE ON ai_meeting_prep
  FOR EACH ROW
  EXECUTE FUNCTION update_ai_meeting_prep_updated_at();

-- Auto-cleanup of expired prep data (optional - can be run as a cron job)
-- DELETE FROM ai_meeting_prep WHERE expires_at < CURRENT_TIMESTAMP;

COMMENT ON TABLE ai_meeting_prep IS 'AI-generated meeting preparation briefs';
COMMENT ON COLUMN ai_meeting_prep.meeting_summary IS 'AI-generated summary of the meeting purpose';
COMMENT ON COLUMN ai_meeting_prep.attendee_context IS 'Information about each attendee (past meetings, emails, etc.)';
COMMENT ON COLUMN ai_meeting_prep.related_emails IS 'Relevant email threads related to this meeting';
COMMENT ON COLUMN ai_meeting_prep.past_meetings IS 'Previous calendar events with same attendees';
COMMENT ON COLUMN ai_meeting_prep.discussion_topics IS 'AI-suggested topics to discuss';
COMMENT ON COLUMN ai_meeting_prep.suggested_questions IS 'AI-suggested questions to ask';
COMMENT ON COLUMN ai_meeting_prep.preparation_checklist IS 'Tasks to complete before the meeting';
COMMENT ON COLUMN ai_meeting_prep.estimated_prep_time IS 'Estimated preparation time in minutes';




