-- ========== Backend\src\database\migrations\create_oauth_temp_tokens_table.sql ==========

-- Create oauth_temp_tokens table for temporary OAuth tokens
-- This table is used to store temporary tokens during the OAuth flow (e.g., Twitter)

-- Enable UUID extension if not already enabled
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Ensure PKCE columns exist (base table may have been created without them)
ALTER TABLE oauth_temp_tokens 
ADD COLUMN IF NOT EXISTS code_verifier TEXT,
ADD COLUMN IF NOT EXISTS state TEXT;

CREATE TABLE IF NOT EXISTS oauth_temp_tokens (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID REFERENCES users(id) ON DELETE CASCADE, -- Changed from UUID to INTEGER to match users table
    platform VARCHAR(20) NOT NULL, -- 'twitter', 'telegram'
    oauth_token TEXT NOT NULL,
    oauth_token_secret TEXT, -- For OAuth 1.0a, not strictly needed for OAuth 2.0 PKCE but kept for flexibility
    code_verifier TEXT, -- For OAuth 2.0 PKCE
    state TEXT, -- For OAuth 2.0 PKCE
    expires_at TIMESTAMP NOT NULL,
    created_at TIMESTAMP DEFAULT NOW(),
    UNIQUE(user_id, platform)
);

-- Add comments for documentation
COMMENT ON TABLE oauth_temp_tokens IS 'Stores temporary OAuth tokens during authentication flows.';
COMMENT ON COLUMN oauth_temp_tokens.user_id IS 'ID of the user initiating the OAuth flow.';
COMMENT ON COLUMN oauth_temp_tokens.platform IS 'Social media platform (e.g., twitter).';
COMMENT ON COLUMN oauth_temp_tokens.oauth_token IS 'Temporary OAuth token or authorization code.';
COMMENT ON COLUMN oauth_temp_tokens.oauth_token_secret IS 'Temporary OAuth token secret (for OAuth 1.0a).';
COMMENT ON COLUMN oauth_temp_tokens.code_verifier IS 'PKCE code verifier for OAuth 2.0.';
COMMENT ON COLUMN oauth_temp_tokens.state IS 'OAuth state parameter for CSRF protection.';
COMMENT ON COLUMN oauth_temp_tokens.expires_at IS 'Timestamp when the temporary token expires.';

-- Create index for performance
CREATE INDEX IF NOT EXISTS idx_oauth_temp_tokens_user_platform ON oauth_temp_tokens(user_id, platform);
CREATE INDEX IF NOT EXISTS idx_oauth_temp_tokens_expires ON oauth_temp_tokens(expires_at);



-- ========== Backend\src\database\migrations\create_reminder_preferences.sql ==========

-- Meeting Reminder Preferences Table
-- Stores user preferences for automated email reminders

CREATE TABLE IF NOT EXISTS meeting_reminder_preferences (
  id SERIAL PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  
  -- Pre-meeting reminders
  enable_pre_meeting_reminders BOOLEAN DEFAULT true,
  reminder_minutes_before INTEGER DEFAULT 30, -- 30 minutes before meeting
  
  -- Daily digest
  enable_daily_digest BOOLEAN DEFAULT true,
  daily_digest_time TIME DEFAULT '08:00:00', -- 8:00 AM local time
  daily_digest_timezone VARCHAR(100) DEFAULT 'UTC',
  
  -- Weekly preview
  enable_weekly_preview BOOLEAN DEFAULT true,
  weekly_preview_day INTEGER DEFAULT 0, -- 0 = Sunday, 1 = Monday, etc.
  weekly_preview_time TIME DEFAULT '18:00:00', -- 6:00 PM local time
  
  -- Email preferences
  include_ai_insights BOOLEAN DEFAULT true, -- Include AI prep in reminders
  
  -- Metadata
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  
  -- Constraints
  UNIQUE(user_id)
);

-- Reminder tracking table (to avoid duplicate sends)
CREATE TABLE IF NOT EXISTS meeting_reminders_sent (
  id SERIAL PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  event_id INTEGER REFERENCES calendar_events(id) ON DELETE CASCADE,
  reminder_type VARCHAR(50) NOT NULL, -- 'pre_meeting', 'daily_digest', 'weekly_preview'
  sent_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_reminder_prefs_user_id ON meeting_reminder_preferences(user_id);
CREATE INDEX IF NOT EXISTS idx_reminders_sent_user_id ON meeting_reminders_sent(user_id);
CREATE INDEX IF NOT EXISTS idx_reminders_sent_event_id ON meeting_reminders_sent(event_id);
