-- ========== Backend\src\database\migrations\create_voice_chat_tables_v2.sql ==========

-- Voice Chat Migration v2 (Safe)
-- Create conversations and messages tables for voice chat functionality
-- This version safely handles existing tables

-- Conversations table
CREATE TABLE IF NOT EXISTS conversations (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    agent_id UUID NOT NULL REFERENCES ai_agents(id) ON DELETE CASCADE,
    status VARCHAR(20) DEFAULT 'active' CHECK (status IN ('active', 'ended', 'paused')),
    title VARCHAR(200), -- Optional conversation title
    voice_settings JSONB DEFAULT '{}', -- Voice preferences, speed, etc.
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Conversation messages table
CREATE TABLE IF NOT EXISTS conversation_messages (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    conversation_id UUID NOT NULL REFERENCES conversations(id) ON DELETE CASCADE,
    role VARCHAR(20) NOT NULL CHECK (role IN ('user', 'assistant', 'system')),
    content TEXT NOT NULL, -- Text content of the message
    audio_url TEXT, -- URL to audio file (if voice message)
    audio_duration_ms INTEGER, -- Duration in milliseconds
    metadata JSONB DEFAULT '{}', -- Additional data like transcription confidence, etc.
    created_at TIMESTAMP DEFAULT NOW()
);

-- Voice settings table for widget configuration
CREATE TABLE IF NOT EXISTS voice_settings (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    widget_id VARCHAR(100), -- Reference to widget instance
    enabled BOOLEAN DEFAULT true,
    auto_transcribe BOOLEAN DEFAULT true,
    speech_to_text_config JSONB DEFAULT '{}',
    text_to_speech_config JSONB DEFAULT '{}',
    voice_language VARCHAR(10) DEFAULT 'en-US',
    voice_speed DECIMAL(3,2) DEFAULT 1.0,
    voice_provider VARCHAR(50) DEFAULT 'openai', -- openai, elevenlabs, etc.
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Create indexes only if they don't exist
DO $$
BEGIN
    -- Indexes for conversations table (only if voice-chat columns exist; table may be group-chat schema)
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversations_user_agent')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversations' AND column_name = 'user_id')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversations' AND column_name = 'agent_id') THEN
        CREATE INDEX idx_conversations_user_agent ON conversations(user_id, agent_id);
    END IF;
    
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversations_status')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversations' AND column_name = 'status') THEN
        CREATE INDEX idx_conversations_status ON conversations(status);
    END IF;
    
    -- Indexes for conversation_messages table
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversation_messages_conversation_id') THEN
        CREATE INDEX idx_conversation_messages_conversation_id ON conversation_messages(conversation_id);
    END IF;
    
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversation_messages_role')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversation_messages' AND column_name = 'role') THEN
        CREATE INDEX idx_conversation_messages_role ON conversation_messages(role);
    END IF;
    
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversation_messages_created_at') THEN
        CREATE INDEX idx_conversation_messages_created_at ON conversation_messages(created_at);
    END IF;
    
    -- Indexes for voice_settings table
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_voice_settings_user_id') THEN
        CREATE INDEX idx_voice_settings_user_id ON voice_settings(user_id);
    END IF;
END $$;

-- Create trigger function if it doesn't exist
CREATE OR REPLACE FUNCTION update_conversations_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    UPDATE conversations SET updated_at = NOW() WHERE id = NEW.conversation_id;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger if it doesn't exist
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname = 'update_conversations_on_message_insert') THEN
        CREATE TRIGGER update_conversations_on_message_insert
            AFTER INSERT ON conversation_messages
            FOR EACH ROW
            EXECUTE FUNCTION update_conversations_updated_at();
    END IF;
END $$;



-- ========== Backend\src\database\migrations\create_voice_chat_tables_v3.sql ==========

-- Voice Chat Migration v3 (Safe with Alter)
-- Handle existing tables with wrong schema

-- Drop existing tables if they have wrong schema (optional - uncomment if needed)
-- DROP TABLE IF EXISTS conversation_messages CASCADE;
-- DROP TABLE IF EXISTS conversations CASCADE;
-- DROP TABLE IF EXISTS voice_settings CASCADE;

-- Check if conversation_messages table exists and alter if needed
DO $$
BEGIN
    -- Check if table exists but doesn't have role column
    IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'conversation_messages') 
       AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversation_messages' AND column_name = 'role') THEN
        RAISE NOTICE 'conversation_messages table exists but missing role column - recreating...';
        DROP TABLE IF EXISTS conversation_messages CASCADE;
    END IF;
END $$;

-- Check if conversations table exists but has wrong schema
DO $$
BEGIN
    -- Check if table exists but user_id is wrong type (UUID instead of INTEGER)
    IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'conversations') 
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversations' AND column_name = 'user_id' AND data_type = 'uuid') THEN
        RAISE NOTICE 'conversations table exists but user_id is UUID instead of INTEGER - recreating...';
        DROP TABLE IF EXISTS conversations CASCADE;
    END IF;
END $$;

-- Conversations table
CREATE TABLE IF NOT EXISTS conversations (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    agent_id UUID NOT NULL REFERENCES ai_agents(id) ON DELETE CASCADE,
    status VARCHAR(20) DEFAULT 'active' CHECK (status IN ('active', 'ended', 'paused')),
    title VARCHAR(200), -- Optional conversation title
    voice_settings JSONB DEFAULT '{}', -- Voice preferences, speed, etc.
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Conversation messages table
CREATE TABLE IF NOT EXISTS conversation_messages (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    conversation_id UUID NOT NULL REFERENCES conversations(id) ON DELETE CASCADE,
    role VARCHAR(50) NOT NULL CHECK (role IN ('user', 'agent', 'system')),
    content TEXT, -- Text content of the message (can be null for audio-only)
    audio_url TEXT, -- URL to audio file (if voice message)
    audio_duration_ms INTEGER, -- Duration in milliseconds
    metadata JSONB DEFAULT '{}', -- Additional data like transcription confidence, etc.
    created_at TIMESTAMP DEFAULT NOW()
);

-- Voice settings table for widget configuration
CREATE TABLE IF NOT EXISTS voice_settings (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID REFERENCES users(id) ON DELETE CASCADE,
    widget_id VARCHAR(100), -- Reference to widget instance
    enabled BOOLEAN DEFAULT true,
    auto_transcribe BOOLEAN DEFAULT true,
    speech_to_text_config JSONB DEFAULT '{}',
    text_to_speech_config JSONB DEFAULT '{}',
    voice_language VARCHAR(10) DEFAULT 'en-US',
    voice_speed DECIMAL(3,2) DEFAULT 1.0,
    voice_provider VARCHAR(50) DEFAULT 'openai', -- openai, elevenlabs, etc.
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Create indexes only if they don't exist
DO $$
BEGIN
    -- Indexes for conversations table (only if voice-chat columns exist; table may be group-chat schema)
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversations_user_agent')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversations' AND column_name = 'user_id')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversations' AND column_name = 'agent_id') THEN
        CREATE INDEX idx_conversations_user_agent ON conversations(user_id, agent_id);
    END IF;
    
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversations_status')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversations' AND column_name = 'status') THEN
        CREATE INDEX idx_conversations_status ON conversations(status);
    END IF;
    
    -- Indexes for conversation_messages table
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversation_messages_conversation_id') THEN
        CREATE INDEX idx_conversation_messages_conversation_id ON conversation_messages(conversation_id);
    END IF;
    
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversation_messages_role')
       AND EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'conversation_messages' AND column_name = 'role') THEN
        CREATE INDEX idx_conversation_messages_role ON conversation_messages(role);
    END IF;
    
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_conversation_messages_created_at') THEN
        CREATE INDEX idx_conversation_messages_created_at ON conversation_messages(created_at);
    END IF;
    
    -- Indexes for voice_settings table
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = 'idx_voice_settings_user_id') THEN
        CREATE INDEX idx_voice_settings_user_id ON voice_settings(user_id);
    END IF;
END $$;

-- Create trigger function if it doesn't exist
CREATE OR REPLACE FUNCTION update_conversations_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    UPDATE conversations SET updated_at = NOW() WHERE id = NEW.conversation_id;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger if it doesn't exist
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname = 'update_conversations_on_message_insert') THEN
        CREATE TRIGGER update_conversations_on_message_insert
            AFTER INSERT ON conversation_messages
            FOR EACH ROW
            EXECUTE FUNCTION update_conversations_updated_at();
    END IF;
END $$;

-- Add helpful comments
COMMENT ON TABLE conversations IS 'Voice chat conversation sessions';
COMMENT ON TABLE conversation_messages IS 'Individual messages within conversations';
COMMENT ON TABLE voice_settings IS 'User voice preferences and TTS/STT config';



-- ========== Backend\src\database\migrations\create_voice_chat_tables.sql ==========

-- Voice Chat Tables
-- Stores voice conversations and messages

-- Voice Conversations
CREATE TABLE IF NOT EXISTS voice_conversations (
    id VARCHAR(50) PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    agent_id VARCHAR(50) NOT NULL,
    title VARCHAR(200) NOT NULL,
    voice_settings JSONB,
    started_at TIMESTAMP DEFAULT NOW(),
    ended_at TIMESTAMP,
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Voice Messages
CREATE TABLE IF NOT EXISTS voice_messages (
    id VARCHAR(50) PRIMARY KEY,
    conversation_id VARCHAR(50) NOT NULL REFERENCES voice_conversations(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    role VARCHAR(20) NOT NULL, -- 'user', 'agent', 'system'
    content TEXT NOT NULL,
    audio_url TEXT,
    audio_duration_ms INTEGER,
    transcription TEXT,
    created_at TIMESTAMP DEFAULT NOW()
);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_voice_conversations_user_id ON voice_conversations(user_id);
CREATE INDEX IF NOT EXISTS idx_voice_conversations_agent_id ON voice_conversations(agent_id);
CREATE INDEX IF NOT EXISTS idx_voice_conversations_started_at ON voice_conversations(started_at);
CREATE INDEX IF NOT EXISTS idx_voice_messages_conversation_id ON voice_messages(conversation_id);
CREATE INDEX IF NOT EXISTS idx_voice_messages_user_id ON voice_messages(user_id);
CREATE INDEX IF NOT EXISTS idx_voice_messages_created_at ON voice_messages(created_at);

-- Update trigger for timestamps
CREATE OR REPLACE FUNCTION update_voice_conversations_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trigger_update_voice_conversations_updated_at ON voice_conversations;
CREATE TRIGGER trigger_update_voice_conversations_updated_at
    BEFORE UPDATE ON voice_conversations
    FOR EACH ROW
    EXECUTE FUNCTION update_voice_conversations_updated_at();

-- Comments for documentation
COMMENT ON TABLE voice_conversations IS 'Voice chat conversations between users and AI agents';
COMMENT ON TABLE voice_messages IS 'Individual messages within voice conversations';
COMMENT ON COLUMN voice_conversations.voice_settings IS 'JSON settings for voice synthesis and recognition';
COMMENT ON COLUMN voice_messages.role IS 'Message role: user, agent, or system';
COMMENT ON COLUMN voice_messages.audio_url IS 'URL to audio file for voice messages';
COMMENT ON COLUMN voice_messages.transcription IS 'Text transcription of voice message';


